parameters.jsCode:
const data   = $input.first().json;
const inputs = $('Normalize Inputs').first().json;

const organic = (data.organic_results || []).slice(0, 8).map((r, i) => ({
  rank: i + 1,
  title:   r.title   || '',
  snippet: r.snippet || ''
}));

const paa     = (data.related_questions || []).slice(0, 8).map(q => q.question || '').filter(Boolean);
const related = (data.related_searches  || []).slice(0, 8).map(s => s.query    || '').filter(Boolean);
const featured = data.answer_box?.answer || data.answer_box?.snippet || 'None';

const serpSummary =
`KEYWORD: "${inputs.keyword}"

TOP RANKING PAGES:
${organic.map(r => `${r.rank}. [${r.title}] — ${r.snippet}`).join('\n')}

PEOPLE ALSO ASK:
${paa.length ? paa.map((q,i) => `${i+1}. ${q}`).join('\n') : 'None found'}

RELATED SEARCHES: ${related.join(', ') || 'None'}
FEATURED SNIPPET: ${featured}`;

return [{ json: {
  keyword:          inputs.keyword,
  tone:             inputs.tone,
  target_word_count:inputs.target_word_count,
  email_to:         inputs.email_to,
  website_niche:    inputs.website_niche,
  serp_summary:     serpSummary,
  paa_questions:    paa,
  related_searches: related
}}];

