parameters.jsCode:
const raw      = $input.first().json;
const aiText   = raw.choices?.[0]?.message?.content || '';
const serpData = $('Extract SERP Data').first().json;

let brief = {};
try {
  const cleaned = aiText.replace(/```json\n?/g,'').replace(/```\n?/g,'').trim();
  brief = JSON.parse(cleaned);
} catch(e) {
  const match = aiText.match(/\{[\s\S]*\}/);
  try   { brief = JSON.parse(match?.[0] || '{}'); }
  catch { brief = { error: 'JSON parse failed', raw: aiText }; }
}

brief.generated_at        = new Date().toISOString();
brief.keyword_queried     = serpData.keyword;
brief.paa_questions_found = serpData.paa_questions  || [];
brief.related_searches    = serpData.related_searches || [];

// Build HTML email
const outlineHtml = (brief.outline || []).map(item =>
  `<${item.level} style="margin:8px 0">${item.heading}</${item.level}><p style="color:#555;font-size:13px;margin:4px 0 12px">${item.notes||''}</p>`
).join('');

const faqHtml = (brief.faq_section || []).map(f =>
  `<li><strong>${f.question}</strong><br><em>${f.answer_hint||''}</em></li>`
).join('');

const htmlEmail = `<html><body style="font-family:Arial,sans-serif;max-width:700px;margin:auto;padding:20px;color:#333">
<h1 style="color:#1a73e8">📋 SEO Content Brief</h1>
<h2>${brief.target_keyword || serpData.keyword}</h2>
<p><strong>Generated:</strong> ${new Date().toLocaleDateString()}</p><hr>
<h3>🎯 Title Options</h3><ol>${(brief.title_options||[]).map(t=>`<li>${t}</li>`).join('')}</ol>
<h3>📝 Meta Description</h3><p style="background:#f5f5f5;padding:10px;border-radius:6px">${brief.meta_description||''}</p>
<h3>🔍 SEO Details</h3>
<table style="width:100%;border-collapse:collapse">
<tr><td style="padding:6px;border:1px solid #ddd"><strong>Search Intent</strong></td><td style="padding:6px;border:1px solid #ddd">${brief.search_intent||''}</td></tr>
<tr><td style="padding:6px;border:1px solid #ddd"><strong>Content Type</strong></td><td style="padding:6px;border:1px solid #ddd">${brief.content_type||''}</td></tr>
<tr><td style="padding:6px;border:1px solid #ddd"><strong>Word Count</strong></td><td style="padding:6px;border:1px solid #ddd">${brief.recommended_word_count||''}</td></tr>
<tr><td style="padding:6px;border:1px solid #ddd"><strong>Difficulty</strong></td><td style="padding:6px;border:1px solid #ddd">${brief.estimated_difficulty||''}</td></tr>
</table>
<h3>🔑 Secondary Keywords</h3><p>${(brief.secondary_keywords||[]).join(', ')}</p>
<h3>📐 Outline</h3>${outlineHtml}
<h3>❓ FAQ</h3><ul>${faqHtml}</ul>
<h3>💡 Content Gaps</h3><ul>${(brief.content_gaps||[]).map(g=>`<li>${g}</li>`).join('')}</ul>
<h3>🏆 Competitor Insights</h3><p>${brief.competitor_insights||''}</p>
<h3>📢 CTA</h3><p>${brief.cta_recommendation||''}</p>
<hr><p style="color:#999;font-size:12px">Auto-generated by n8n | AI Automation Expert</p>
</body></html>`;

return [{ json: { brief, html_email: htmlEmail, email_to: serpData.email_to, keyword: serpData.keyword } }];
